// Store the incoming snapshot in workflow static data
const snapshot = $input.item.json.body || $input.item.json;
const staticData = $getWorkflowStaticData('global');
staticData.lastSnapshot = JSON.stringify(snapshot);
staticData.snapshotAt = new Date().toISOString();
// Clear any pending patch when new snapshot arrives
staticData.pendingPatch = null;
return { json: { ok: true, taskCount: (snapshot.tasks||[]).length, snapshotAt: staticData.snapshotAt } };

// Return pending patch if one exists, otherwise empty
const staticData = $getWorkflowStaticData('global');
const patch = staticData.pendingPatch ? JSON.parse(staticData.pendingPatch) : { updates: [] };
// Clear after pulling
if(staticData.pendingPatch) staticData.pendingPatch = null;
return { json: patch };

// Store Claude's patch for OdTauLai to pull
const patch = $input.item.json.body || $input.item.json;
const staticData = $getWorkflowStaticData('global');
staticData.pendingPatch = JSON.stringify(patch);
return { json: { ok: true, updateCount: (patch.updates||[]).length } };
